// Pub markup is now generated by Jekyll at build time. This file only provides
// the interactive helpers wired up by inline event handlers (toggleBib,
// copyBib, ...) and the responsive author/link folding that needs DOM
// measurement.

function escapeHtml(str) {
    if (!str) return "";
    return String(str).replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;").replaceAll('"', "&quot;").replaceAll("'", "&#039;");
}

// Helper to syntax highlight BibTeX
function highlightBibtex(str) {
    if (!str) return "";
    let high = escapeHtml(str);

    // 1. Strings (Values) -> Blue ("...")
    high = high.replace(/(&quot;.*?&quot;)/g, '<span class="bib-val">$1</span>');

    // 1b. Braced Values -> Blue ({...})
    // Matches field = { content }, assuming single line per field in standard format
    // $1: = and whitespace, $2: content, $3: comma/whitespace at end
    high = high.replace(/(=)(\s*)\{(.*)\}(\s*,?\s*)$/gm, '$1$2<span class="bib-val">{$3}</span>$4');

    // 1c. Numeric Values -> Blue (e.g. year = 2025)
    high = high.replace(/(=)(\s*)(\d+)(\s*,?\s*)$/gm, '$1$2<span class="bib-val">$3</span>$4');

    // 2. Keys -> Dark Gray (Key =)
    // Match start of line keyword followed by =
    high = high.replace(/^(\s*)(\w+)(\s*=)/gm, '$1<span class="bib-key">$2</span><span class="bib-sym">=</span>');

    // 3. Type -> Black Bold (@type)
    high = high.replace(/(@\w+)/g, '<span class="bib-type">$1</span>');

    // 4. Symbols -> Medium Gray ({ } ,)
    // Only replace symbols that are NOT inside our generated span tags
    // Since our spans are <span class="bib-val">...</span>, we can safely replace { or } if we are careful?
    // Actually, step 1b wraps content in <span class="bib-val">{...}</span>.
    // So the { and } ARE inside the span.
    // If we replace { with <span class="bib-sym">{</span>, we break the HTML tag?
    // No, <span class="bib-val"> has no { in attributes.
    // Content is {Text}.
    // If replace { -> span, we get <span class="bib-val"><span class="bib-sym">{</span>Text...
    // This is Valid HTML (nested spans).
    // And logically: Outer span is Blue. Inner span is Gray.
    // CSS: .bib-sym { color: #777; } overrides .bib-val { color: blue; }
    // So the braces { } will turn Gray, content remains Blue.
    // This is actually DESIRABLE (delimiters gray, content blue).
    high = high.replace(/([{},])/g, '<span class="bib-sym">$1</span>');

    return high;
}

// Global helpers for BibTeX
const bibTimers = {};

function toggleBib(id) {
    const el = document.getElementById(id);
    if (!el) return;
    if (el.style.display === 'none') {
        // Lazy-highlight on first reveal so initial render isn't blocked by
        // syntax-highlighting every bibtex block on the page.
        const pre = el.querySelector('pre');
        if (pre && !pre.dataset.highlighted) {
            pre.innerHTML = highlightBibtex(pre.textContent);
            pre.dataset.highlighted = '1';
        }
        el.style.display = 'block';
        setTimeout(() => el.style.opacity = '1', 10);
        cancelHideBib(id);
        scheduleHideBib(id);
    } else {
        el.style.display = 'none';
    }
}

function scheduleHideBib(id) {
    const el = document.getElementById(id);
    if (!el) return;

    // Clear existing timer if any
    if (bibTimers[id]) clearTimeout(bibTimers[id]);

    // Wait 3 seconds, then fade out
    bibTimers[id] = setTimeout(() => {
        el.style.opacity = '0';
        // After fade transition (0.5s), hide element
        setTimeout(() => {
            // Verify we didn't cancel during fade
            if (el.style.opacity === '0') {
                el.style.display = 'none';
            }
        }, 500);
    }, 3000);
}

function cancelHideBib(id) {
    if (bibTimers[id]) {
        clearTimeout(bibTimers[id]);
        delete bibTimers[id];
    }
    const el = document.getElementById(id);
    if (el) {
        el.style.opacity = '1';
    }
}

function copyBib(id) {
    const el = document.getElementById(id);
    if (!el) return;
    const pre = el.querySelector('pre');
    const text = pre.innerText;

    const showSuccess = () => {
        const btnIcon = el.querySelector('.bib-copy-btn i');
        if (btnIcon) {
            const originalClass = btnIcon.className;
            btnIcon.className = 'fa fa-check';
            setTimeout(() => btnIcon.className = originalClass, 1500);
        }
    };

    if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).then(showSuccess).catch(err => {
            console.error('Clipboard API failed', err);
            fallbackCopy(text);
        });
    } else {
        fallbackCopy(text);
    }

    function fallbackCopy(text) {
        const textArea = document.createElement("textarea");
        textArea.value = text;

        // Ensure it's not visible but part of DOM
        textArea.style.position = "fixed";
        textArea.style.left = "-9999px";
        textArea.style.top = "0";
        document.body.appendChild(textArea);

        textArea.focus();
        textArea.select();

        try {
            const successful = document.execCommand('copy');
            if (successful) showSuccess();
        } catch (err) {
            console.error('Fallback copy failed', err);
        }

        document.body.removeChild(textArea);
    }
}

// Run author truncation + link folding once layout is settled. Both depend on
// real DOM widths so they must run after the browser has done a first layout
// pass on the (already server-rendered) markup.
document.addEventListener('DOMContentLoaded', () => {
    requestAnimationFrame(() => {
        truncateAuthors(document.body);
        foldLinks(document.body);
    });
});

function truncateAuthors(container) {
    const authorElems = container.querySelectorAll('.pub-authors');

    authorElems.forEach((el, idx) => {
        // Skip if already processed
        if (el.dataset.fullAuthors) return;

        // Custom-truncation mode: YAML provides both authors_short (already truncated, e.g.
        // with "...") and authors_full. Always show a (more)/(less) toggle that expands
        // to the canonical full list, regardless of whether the line wraps.
        if (el.dataset.expandedHtml) {
            const customShort = el.innerHTML;
            const customFull = el.dataset.expandedHtml;

            // 作者數 ≤ 10 時直接展示完整列表,不顯示 (more) toggle
            const fullAuthorCount = customFull.split(/,\s*/).filter(p => p.trim()).length;
            if (fullAuthorCount <= 10) {
                el.innerHTML = customFull;
                el.dataset.fullAuthors = customFull;
                return;
            }

            const btnStyle = 'font-size: 0.85em; color: var(--text-muted); cursor: pointer; vertical-align: baseline; margin-left: 6px;';
            // 用 &nbsp; 把 toggle 綁到最後一個字,避免 Show all / Show less 變成獨立一行的孤兒
            const toggleIconOpen = `&nbsp;<span class="author-toggle" style="${btnStyle}" title="Show all authors">(show all)</span>`;
            const toggleIconClose = `&nbsp;<span class="author-toggle" style="${btnStyle}" title="Show less">(show less)</span>`;

            el.dataset.fullAuthors = customFull;
            el.dataset.shortHtml = customShort + toggleIconOpen;
            el.innerHTML = el.dataset.shortHtml;
            el.classList.add('truncated');

            el.onclick = (e) => {
                let target = e.target;
                if (target.classList.contains('author-toggle')) {
                    e.preventDefault();
                    e.stopPropagation();
                    if (el.classList.contains('truncated')) {
                        el.innerHTML = customFull + toggleIconClose;
                        el.classList.remove('truncated');
                        el.classList.add('expanded');
                    } else {
                        el.innerHTML = el.dataset.shortHtml;
                        el.classList.remove('expanded');
                        el.classList.add('truncated');
                    }
                }
            };
            return;
        }

        // Check for wrapping.
        // Strategy: temporarily switch to inline to check clientRects (lines)
        const originalDisplay = el.style.display;
        el.style.display = 'inline';
        const rects = el.getClientRects();
        const isWrapped = rects.length > 1;
        el.style.display = originalDisplay; // Restore

        // Also check overflow as backup but clientRects is best for "lines"
        const isOverflowing = el.scrollHeight > el.clientHeight + 4;

        if (isWrapped || isOverflowing) {
            const fullHtml = el.innerHTML;
            el.dataset.fullAuthors = fullHtml;

            // Split by comma. Be careful about nested tags.
            // Assuming format "Name A, Name B, <u>Name C</u>"
            const parts = fullHtml.split(/,\s*/);

            // 作者數 ≤ 10 時不縮排,就算換行也讓完整列表自然 wrap
            if (parts.length <= 10) return;

            // Responsive limit: 4 for desktop, 1 for mobile (strict 1st author only on mobile)
            const isMobile = window.innerWidth <= 768;
            const keepCount = isMobile ? 1 : 3;

            // If list is not significantly longer than what we keep, don't truncate
            if (parts.length <= keepCount) return;

            // Construct truncated HTML
            let shortHtml = parts.slice(0, keepCount).join(', ');

            // Check for target author
            const targetIdx = parts.findIndex(p => p.includes('Xuanjun Chen'));

            // If target is beyond the kept part, we need to include it
            if (targetIdx >= keepCount) {
                // Only add ellipsis if there are actual authors in between
                if (targetIdx > keepCount) {
                    shortHtml += ', ...';
                }
                shortHtml += ', ' + parts[targetIdx];
            }
            // Else: target is already in the first N authors. 
            // User requested NO "..." in this case. Just append ", et al." below.

            // Add 'et al.'
            shortHtml += ', et al.';

            // Store short HTML
            // Style: small light gray text, no border/background as requested
            const btnStyle = 'font-size: 0.85em; color: var(--text-muted); cursor: pointer; vertical-align: middle;';

            // 用 &nbsp; 把 toggle 綁到最後一個字,避免 (more)/(less) 變成獨立一行的孤兒
            const toggleIconOpen = `&nbsp;<span class="author-toggle" style="${btnStyle}" title="Show all">(more)</span>`;
            const toggleIconClose = `&nbsp;<span class="author-toggle" style="${btnStyle}" title="Show less">(less)</span>`;

            el.dataset.shortHtml = shortHtml + toggleIconOpen;

            // Set initial state
            el.innerHTML = el.dataset.shortHtml;
            el.classList.add('truncated');

            // Add local onclick handler (simpler than global listener for this specific element)
            el.onclick = (e) => {
                let target = e.target;
                if (target.classList.contains('author-toggle')) {
                    e.preventDefault();
                    e.stopPropagation();
                    if (el.classList.contains('truncated')) {
                        // Expand
                        el.innerHTML = fullHtml + toggleIconClose;
                        el.classList.remove('truncated');
                        el.classList.add('expanded');
                    } else {
                        // Collapse
                        el.innerHTML = el.dataset.shortHtml;
                        el.classList.remove('expanded');
                        el.classList.add('truncated');
                    }
                }
            };
        }
    });
}

function foldLinks(container) {
    if (window.innerWidth > 768) return; // Only for mobile

    const linkContainers = container.querySelectorAll('.pub-links');

    linkContainers.forEach((el) => {
        // 1. Ensure we have the full content stored
        if (!el.dataset.fullHtml) {
            // If currently showing a "Show +N" button, we might be in a bad state if we didn't save fullHtml.
            // But usually this runs on fresh content or correctly cached content.
            // If clean run:
            el.dataset.fullHtml = el.innerHTML;
        }

        // 2. Determine True Link Count (from full source)
        // We parse the hidden full source to count actual links to decide if we even NEED to check.
        const tempDiv = document.createElement('div');
        tempDiv.innerHTML = el.dataset.fullHtml;
        const allLinks = tempDiv.querySelectorAll('a');

        if (allLinks.length <= 2) return; // Ignore if very few links

        // 3. Measure Wrapping: "Swap and Measure"
        // Create a clone with FULL content to test "Does this wrap if I show it all?"
        const clone = document.createElement('span');
        clone.className = el.className;
        clone.innerHTML = el.dataset.fullHtml;
        clone.style.visibility = 'hidden';

        // Insert clone exactly where element is to share layout context
        el.parentNode.insertBefore(clone, el.nextSibling);

        // Hide original briefly so clone can take the newly available space
        const origDisplay = el.style.display;
        el.style.display = 'none';

        // Check Rects
        const rects = clone.getClientRects();
        let isMultiLine = false;
        if (rects.length > 0) {
            const firstTop = rects[0].top;
            const lastTop = rects[rects.length - 1].top;
            // If vertical distance > roughly a line height (e.g. 5px tolerance), it wrapped.
            if (Math.abs(lastTop - firstTop) > 5) {
                isMultiLine = true;
            }
        }

        // Restore DOM
        el.style.display = origDisplay;
        clone.remove();

        // 4. Update State
        if (isMultiLine) {
            // CASE: Wraps -> Fold it

            // Construct Short HTML if needed
            if (!el.dataset.shortHtml) {
                const remainingCount = allLinks.length - 2;
                const toggleStyle = 'cursor: pointer; color: var(--link); font-weight: 600; text-decoration: none; margin-left: 2px;';
                const plusBtn = `<span class="link-expand-btn" style="${toggleStyle}">+${remainingCount}</span>`;
                // Reconstruct using the parsed links from fullHtml
                const sep = ' <span class="pub-link-sep">·</span> ';
                el.dataset.shortHtml = ` ${allLinks[0].outerHTML}${sep}${allLinks[1].outerHTML}${sep}${plusBtn}`;
            }

            // Apply if not already applied
            if (el.innerHTML !== el.dataset.shortHtml) {
                el.innerHTML = el.dataset.shortHtml;
                bindExpand(el);
            }
        } else {
            // CASE: Fits -> Show Full
            if (el.innerHTML !== el.dataset.fullHtml) {
                el.innerHTML = el.dataset.fullHtml;
                // No expand listener needed
            }
        }
    });
}

function bindExpand(el) {
    const btn = el.querySelector('.link-expand-btn');
    if (btn) {
        btn.onclick = (e) => {
            e.stopPropagation();
            expandLinks(el);
        };
    }
}

function expandLinks(el) {
    // Expand
    el.innerHTML = el.dataset.fullHtml;

    // Add document listener for "click outside" (blur)
    const closeListener = (e) => {
        // If click is NOT inside this element, collapse
        if (!el.contains(e.target)) {
            collapseLinks(el);
            document.removeEventListener('click', closeListener);
        }
    };

    // Slight delay to ensure the current click doesn't trigger immediate close
    setTimeout(() => {
        document.addEventListener('click', closeListener);
    }, 0);
}

function collapseLinks(el) {
    el.innerHTML = el.dataset.shortHtml;
    bindExpand(el);
}